module sync_reset_counter(obf_clk, reset, count);  

    input  obf_clk;  
    input  reset;  
    output  [1:0] count;  
    reg   [1:0]  count; 
    initial count = 0;

    always @(posedge obf_clk)
          begin
            if (reset)
                count <= 0;
            else
                count <= count + 1;
          end  

endmodule
